                      <div style={{flex:1}}>
                        <div style={{fontFamily:"Playfair Display,serif",fontWeight:600,fontSize:14,color:"#1A1208"}}>{item.name}</div>
                        <div style={{fontSize:11,color:"#B08050",marginTop:2}}>{item.qty} · {item.reason}</div>
                      </div>
